export function run(input, sdk) {
  const findings = [];

  // inputには run-scan.js から送られたソースコードの文字列がそのまま入ります
  if (typeof input === 'string') {

    // 1. OSコマンドインジェクションの検知
    if (input.includes('exec.Command')) {
      findings.push({
        title: 'OS Command Injection',
        description: '危険な関数 exec.Command が使用されています。OSコマンドインジェクションの可能性があります。',
        severity: 'CRITICAL',
        filePath: '該当ファイル'
      });
    }

    // 2. SQLインジェクションの検知
    if (input.includes("fmt.Sprintf(\"SELECT") || input.includes("fmt.Sprintf(\"UPDATE")) {
      findings.push({
        title: "SQL Injection",
        description: "ユーザー入力を直接SQL文に連結しています。プレースホルダ（?）を使用してください。",
        severity: "CRITICAL",
        filePath: "該当ファイル"
      });
    }

    // 3. ハードコードされたパスワードの検知
    if (input.includes("password = \"") || input.includes("Password = \"")) {
      findings.push({
        title: "Hardcoded Secret",
        description: "ソースコードにパスワードが直接書き込まれています。環境変数を使用してください。",
        severity: "HIGH",
        filePath: "該当ファイル"
      });
    }
  }

  return { findings: findings };
}
